// ===== SINGULARE SCORE COLLECTOR v1.3 =====
// FIX: Doctoralia via URL direta do perfil (zero falsos positivos)
const tenant = $json;
const GOOGLE_API_KEY = $env.GOOGLE_MAPS_API_KEY || '';
const errors = [];

// --- GOOGLE PLACES ---
let g = { rating: null, reviews_count: 0, has_hours: false, has_photos: false, photos_count: 0, verified: false, place_id: tenant.google_place_id };
try {
  if (GOOGLE_API_KEY) {
    let placeId = tenant.google_place_id;
    if (!placeId) {
      const q = [tenant.doctor_name, tenant.speciality, tenant.city].filter(Boolean).join(' ');
      const sd = await this.helpers.httpRequest({ method: 'GET', url: 'https://maps.googleapis.com/maps/api/place/textsearch/json', qs: { query: q, type: 'doctor', language: 'pt-BR', key: GOOGLE_API_KEY } });
      if (sd.results && sd.results.length > 0) { placeId = sd.results[0].place_id; g.place_id = placeId; g.rating = sd.results[0].rating || null; g.reviews_count = sd.results[0].user_ratings_total || 0; }
    }
    if (placeId) {
      const dd = await this.helpers.httpRequest({ method: 'GET', url: 'https://maps.googleapis.com/maps/api/place/details/json', qs: { place_id: placeId, fields: 'rating,user_ratings_total,opening_hours,photos,business_status', language: 'pt-BR', key: GOOGLE_API_KEY } });
      if (dd.result) { g.rating = dd.result.rating || g.rating; g.reviews_count = dd.result.user_ratings_total || g.reviews_count; g.has_hours = !!(dd.result.opening_hours); g.has_photos = !!(dd.result.photos && dd.result.photos.length); g.photos_count = dd.result.photos ? dd.result.photos.length : 0; g.verified = dd.result.business_status === 'OPERATIONAL'; }
    }
  }
} catch (e) { errors.push({ source: 'google', error: e.message }); }

// --- DOCTORALIA v1.3 - URL direta do perfil ---
let d = { present: false, rating: null, reviews_count: 0, url: null, online_booking: false };
try {
  const rawName = (tenant.doctor_name || '').replace(/^(Dra?\.?\s*)/i, '').trim();
  const slug = rawName.toLowerCase()
    .normalize('NFD').replace(/[\u0300-\u036f]/g, '')
    .replace(/\s+/g, '-').replace(/[^a-z0-9-]/g, '');

  const specMap = {
    'reumatologia': 'reumatologista',
    'clinica geral': 'medico-clinico-geral',
    'cardiologia': 'cardiologista',
    'dermatologia': 'dermatologista',
    'ginecologia': 'ginecologista',
    'ortopedia': 'ortopedista-traumatologista',
    'pediatria': 'pediatra',
    'psiquiatria': 'psiquiatra',
    'neurologia': 'neurologista',
    'endocrinologia': 'endocrinologista',
    'urologia': 'urologista',
    'oftalmologia': 'oftalmologista',
    'otorrinolaringologia': 'otorrino',
    'nutrição': 'nutricionista',
    'psicologia': 'psicologo',
    'fisioterapia': 'fisioterapeuta',
    'odontologia': 'dentista'
  };
  const specSlug = specMap[(tenant.speciality || '').toLowerCase()] || 
    (tenant.speciality || 'medico').toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '').replace(/\s+/g, '-');

  const citySlug = (tenant.city || 'sao-paulo').toLowerCase()
    .normalize('NFD').replace(/[\u0300-\u036f]/g, '')
    .replace(/\s+/g, '-');

  const profileUrl = 'https://www.doctoralia.com.br/' + slug + '/' + specSlug + '/' + citySlug;

  try {
    const html = await this.helpers.httpRequest({
      method: 'GET', url: profileUrl,
      headers: { 'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36', 'Accept-Language': 'pt-BR' },
      encoding: 'utf-8', json: false, returnFullResponse: false
    });

    if (typeof html === 'string' && html.length > 5000 && !html.includes('page-not-found') && !html.includes('404')) {
      d.present = true;
      d.url = profileUrl;
      const rm = html.match(/data-rating="([\d.]+)"/);
      if (rm) d.rating = parseFloat(rm[1]);
      const rvm = html.match(/(\d+)\s*opini/i);
      if (rvm) d.reviews_count = parseInt(rvm[1]);
      d.online_booking = html.includes('Agendar consulta') || html.includes('booking-button');
    }
  } catch (profileErr) {
    // 404 ou redirect = perfil nao existe (esperado)
    d.present = false;
  }
} catch (e) { errors.push({ source: 'doctoralia', error: e.message }); }

// --- WEBSITE + PAGESPEED ---
let w = { exists: false, ssl: false, mobile_score: 0, performance_score: 0 };
try {
  if (tenant.website_url) {
    try { await this.helpers.httpRequest({ method: 'HEAD', url: tenant.website_url }); w.exists = true; } catch (e) { w.exists = false; }
    w.ssl = (tenant.website_url || '').startsWith('https');
    if (w.exists && GOOGLE_API_KEY) {
      const pd = await this.helpers.httpRequest({ method: 'GET', url: 'https://www.googleapis.com/pagespeedonline/v5/runPagespeed', qs: { url: tenant.website_url, category: 'performance', strategy: 'mobile', key: GOOGLE_API_KEY } });
      if (pd.lighthouseResult && pd.lighthouseResult.categories) { w.performance_score = Math.round((pd.lighthouseResult.categories.performance?.score || 0) * 100); w.mobile_score = w.performance_score; }
    }
  }
} catch (e) { errors.push({ source: 'website', error: e.message }); }

