let gs = 0;
if (g.rating) gs += Math.min(g.rating / 5.0, 1.0) * 12;
gs += Math.min(g.reviews_count / 50, 1.0) * 10;
if (g.has_hours) gs += 3; gs += Math.min(g.photos_count / 5, 1.0) * 3;
if (g.verified) gs += 2; gs = Math.round(gs);

let ds = 0;
if (d.present) ds += 5;
if (d.rating) ds += Math.min(d.rating / 5.0, 1.0) * 5;
ds += Math.min(d.reviews_count / 30, 1.0) * 3;
if (d.online_booking) ds += 2; ds = Math.round(ds);

let ss = 0; let seo = 0;
if (w.exists) seo += 3; if (w.ssl) seo += 1;
seo += Math.min(w.mobile_score / 50, 1.0) * 2;
seo += Math.min(w.performance_score / 70, 1.0) * 2;
seo = Math.round(seo); let ops = 0;
const total = Math.min(gs + ds + ss + seo + ops, 100);
const classification = total <= 25 ? 'critical' : total <= 50 ? 'developing' : total <= 75 ? 'good' : 'excellent';

const recs = [];
if (!g.place_id) recs.push({ priority: 'high', category: 'google', message: 'Perfil nao encontrado no Google Maps', action: 'Crie um Google Meu Negocio' });
if (g.reviews_count < 10) recs.push({ priority: 'high', category: 'google', message: 'Apenas ' + g.reviews_count + ' avaliacoes no Google', action: 'Ative pedido de review pos-consulta' });
if (!d.present) recs.push({ priority: 'high', category: 'doctoralia', message: 'Sem perfil na Doctoralia', action: 'Crie perfil gratuito em doctoralia.com.br' });
if (!w.exists && !tenant.website_url) recs.push({ priority: 'medium', category: 'website', message: 'Sem site proprio', action: 'Considere criar um site com agendamento online' });

return { tenant_id: tenant.tenant_id, total_score: total, classification, google_score: gs, doctoralia_score: ds, social_score: ss, seo_score: seo, operational_score: ops, google_rating: g.rating, google_reviews_count: g.reviews_count, google_has_hours: g.has_hours, google_has_photos: g.has_photos, google_photos_count: g.photos_count, google_verified: g.verified, doctoralia_present: d.present, doctoralia_rating: d.rating, doctoralia_reviews_count: d.reviews_count, doctoralia_url: d.url, doctoralia_online_booking: d.online_booking, website_exists: w.exists, website_ssl: w.ssl, website_mobile_score: w.mobile_score, website_performance_score: w.performance_score, recommendations: JSON.stringify(recs), collection_errors: JSON.stringify(errors), _place_id_cache: g.place_id };

const d = $json;
const esc = (v) => { if (v === null || v === undefined) return 'NULL'; if (typeof v === 'boolean') return v ? 'TRUE' : 'FALSE'; if (typeof v === 'number') return String(v); return "'" + String(v).replace(/'/g, "''") + "'"; };
const sql = 'INSERT INTO public.tenant_scores (tenant_id, total_score, classification, google_score, doctoralia_score, social_score, seo_score, operational_score, google_rating, google_reviews_count, google_has_hours, google_has_photos, google_photos_count, google_verified, doctoralia_present, doctoralia_rating, doctoralia_reviews_count, doctoralia_url, doctoralia_online_booking, website_exists, website_ssl, website_mobile_score, website_performance_score, recommendations, collection_errors, previous_score, score_change) SELECT ' + esc(d.tenant_id) + ', ' + d.total_score + ', ' + esc(d.classification) + ', ' + d.google_score + ', ' + d.doctoralia_score + ', ' + d.social_score + ', ' + d.seo_score + ', ' + d.operational_score + ', ' + (d.google_rating === null ? 'NULL' : d.google_rating) + ', ' + d.google_reviews_count + ', ' + d.google_has_hours + ', ' + d.google_has_photos + ', ' + d.google_photos_count + ', ' + d.google_verified + ', ' + d.doctoralia_present + ', ' + (d.doctoralia_rating === null ? 'NULL' : d.doctoralia_rating) + ', ' + d.doctoralia_reviews_count + ', ' + esc(d.doctoralia_url) + ', ' + d.doctoralia_online_booking + ', ' + d.website_exists + ', ' + d.website_ssl + ', ' + d.website_mobile_score + ', ' + d.website_performance_score + ', ' + esc(d.recommendations) + '::jsonb, ' + esc(d.collection_errors) + '::jsonb, (SELECT total_score FROM public.tenant_scores WHERE tenant_id = ' + esc(d.tenant_id) + ' ORDER BY collected_at DESC LIMIT 1), ' + d.total_score + ' - COALESCE((SELECT total_score FROM public.tenant_scores WHERE tenant_id = ' + esc(d.tenant_id) + ' ORDER BY collected_at DESC LIMIT 1), ' + d.total_score + ') RETURNING id, tenant_id, total_score, classification, score_change';
return { ...d, _sql: sql };

